// =============================================================================
// CRUD Operations
// =============================================================================

// Insert inserts a new Order record.
func (o *Order) Insert(
	ctx context.Context,
	db tsq.SQLExecutor,
) error {
	o.CreatedAt = tsqtime.Now()
	o.UpdatedAt = null.TimeFrom(tsqtime.Now())
	err := tsq.Insert(ctx, db, o)
	if err != nil {
		return errors.Annotatef(err, "insert Order: %s", tsq.CompactJSON(o))
	}
	return nil
}

// Update updates an existing Order record.
func (o *Order) Update(
	ctx context.Context,
	db tsq.SQLExecutor,
) error {
	o.UpdatedAt = null.TimeFrom(tsqtime.Now())
	err := tsq.Update(ctx, db, o)
	if err != nil {
		return errors.Annotatef(err, "update Order: %s", tsq.CompactJSON(o))
	}
	return nil
}

// Delete permanently removes a Order record.
func (o *Order) Delete(
	ctx context.Context,
	db tsq.SQLExecutor,
) error {
	err := tsq.Delete(ctx, db, o)
	if err != nil {
		return errors.Annotatef(err, "delete Order: %s", tsq.CompactJSON(o))
	}
	return nil
}

// SoftDelete marks a Order record as deleted.
func (o *Order) SoftDelete(
	ctx context.Context,
	db tsq.SQLExecutor,
	dt int64,
) error {
	if dt != 0 {
		o.DeletedAt = dt
	} else {
		o.DeletedAt = tsqtime.Now().UnixNano()
	}
	o.UpdatedAt = null.TimeFrom(tsqtime.Now())
	err := tsq.Update(ctx, db, o)
	if err != nil {
		return errors.Annotatef(err, "soft-delete Order: %s", tsq.CompactJSON(o))
	}
	return nil
}

